INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-03161', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在老年人常見的疾病中，下列描述何者正確？', '["阿茲海默症、巴金森氏症都是屬於可逆性的疾病", "輕度失智症的老人，經常會被家人和專業人員疏忽", "對失智老人的活動安排不能太活潑，才不會過度刺激其病症", "手腳抖動不停是失智患者的重要徵狀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03162', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關人類面臨死亡的過程，下列那一項描述正確？', '["Elizabeth Kubler-Ross提出人在面臨死亡過程的次序為：否認和隔離、接受、討價還價、憂鬱、憤怒", "在實務工作中，Elizabeth Kubler-Ross所提出人在面臨死亡過程會以次序性的方式出現", "臨終關懷（hospice）的概念是1960年代由英國桑德斯（Dr. Cicely Saunders）首先提出", "通常在老人機構和老人談論死亡的相關話題並不是禁忌，故社工人員不需在意"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03163', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關社會資源的描述，下列何者正確？', '["社會資源是指協助社工人員發揮個人潛能，滿足其問題需求的相關資源", "使用正式資源的優點雖需資產調查，但卻缺乏資源重分配之公平效果", "在照顧的過程中，對關係的投入、承諾為經濟性資源，而對權力運作的認知為規範性資源", "社工人員在助人專業過程中，進行外在資源連結是協助案主的重要工具"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03164', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '校園暴力問題已成為學校中令人頭痛的問題，下列那一項描述正確？', '["校園暴力事件大都發生在老師與學生之間，老師和學生都常為被害人", "校園暴力是指發生於學校內或上學期間，所發生的暴力侵害行為", "校園暴力事件的嚴重性，以官方的統計嚴重性較高", "校園暴力問題以居住在犯罪率較高的地區才會發生"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03165', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一項不是「出櫃」（coming out）通常需經歷的階段？', '["自我坦承", "結識圈內人", "向參考團體坦承", "公開自己的性取向"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03166', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在美國，目前法律上已經承認同性婚姻合法的州有多少個？', '["不到10個", "10～19個", "20～29個", "30個以上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03167', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對於「變項（variables）」的敘述，何者正確？', '["社會科學理論的目的之一在描述變項和變項之間的關聯", "變項是由屬性（attributes）所構成的邏輯群聚。例如，性別這個屬性就是男、女這兩個變項所構成", "若我們說「一個人受教育可降低偏見的機率」，在此處偏見是自變項（independent variable），而教育 是依變項（dependent variable）", "抑制變項（suppressor variable）會讓我們所知道的變項關係恰恰與原始資料所提供者相反"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03168', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者在閱讀眾多相關文獻後，想透過大規模的調查找出受虐者為什麼會又回到施虐者身邊同住的理 由。這在研究的目的上，它屬於那類？', '["探索性", "描述性", "解釋性", "一般性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03169', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者想研究青少年中輟的原因，他從觀察開始，然後找出其中模式，並依此提出一套暫時的結論， 在邏輯上，這是什麼方法的應用？', '["類比法", "外推法", "歸納法", "演繹法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03170', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某實務工作者執行脫貧方案，發現它能有效協助當地貧困者脫貧。現在，他打算推廣到其他地方去。但 他又害怕產生研究法中「過度概化（overgeneralization）」的謬誤，這個問題該如何解決？', '["試著給予選擇性的觀察", "試著加大樣本數、並且重複的再觀察這項方案執行的結果", "針對這個現象，請教權威", "這個情形很難避免，做了再說"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03171', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某社會工作研究者想瞭解接受安寧照護病患的經歷、以及這些經歷對患者的深層意義，來提高他們的生 活品質，這類研究較適合採用的典範是：', '["現代主義", "實證主義", "批判主義", "詮釋主義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03172', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某人想藉由觀察團體成員彼此談話中「我們」一詞出現的次數來研究「團體凝聚力」。請問從「團體凝 聚力」到「團體成員對話過程中我們一詞出現的次數」，這個過程在研究法中叫：', '["概念化", "操作化", "抽象化", "量化研究不會出現這種做法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03173', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有位男性身處在以女性為主的社會工作專業中，每當他回答涉及性別議題的問卷時，總是小心翼翼，避 免自己變成男性沙文主義者。請問這種現象是：', '["社會期望的偏誤（social desirability bias）", "隨機性的誤差（random error）", "月暈效應（halo effect）", "順勢反應（acquiescent response set）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03174', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在實務工作中，我們常用非常滿意、滿意、普通、不滿意、非常不滿意來反應服務使用者的意見。姑不 論實際統計操作的權宜作法，它真正的測量尺度是：', '["類別尺度（nominal level）", "順序尺度（ordinal level）", "等距尺度（interval level）", "等比尺度（ratio level）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03175', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某異性戀研究者想研究同性戀者生活網絡，採用何種取樣方式方是合宜？', '["機率抽樣（probability sampling）", "限額抽樣（quota sampling ）", "理論抽樣（theoretical sampling）", "滾雪球抽樣（snowball sampling）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03176', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列量化研究中決定樣本大小的敘述，何者正確？', '["它可由「待分析變項數乘以統計程序所需每個變項之最小樣本數」所決定", "它可由「研究者所決定的抽樣間距（sampling interval）」所決定", "它可由「按數量成比例的機率抽樣（Probability Proportionate to Size Sampling，簡稱PPS）」所決定", "它可由「母群體越小、樣本就必需抽得越大」這項描述所決定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03177', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者發現社區居民需求評量的量表中「社會融合」這項構面的Cronbach α值為0.82。這意味著：', '["這份量表的內容效度高，它可以真正測到社會融合這個構面", "這份量表的受測者在填答社會融合這個構面的不同題項時，它有著高度差異的反應", "這份量表中社會融合構面的建構效度高，它表示其中各個項目間具有高度的一致性", "這份量表在社會融合這項構面中的各個題項相關性高，它在信度上具有內在一致性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03178', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者想研究報紙中低收入戶的公眾意象，這項研究的分析單位（unit of analysis）是：', '["記者本人", "低收入戶本人", "報紙的報導", "社會救助業務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03179', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '針對受霸凌學童，綜合運用諸如社會工作者的個案紀錄、兒童行為檢核表、學校導師紀錄、兒童綜合適 應量表…等多元測量工具來提升研究效度的方法叫：', '["詮釋循環法（hermeneutic circle）", "線性插補法（linear interpolation）", "已知團體效度法（known groups validity）", "三角測量法（triangulation）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03180', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某問卷之問項為「市長應該花更多納稅人的錢，來確保本市市民享有老人津貼的福利」。上述問項犯了 何種錯誤？', '["誘導性", "雙重否定", "事後回溯", "聲望偏誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03181', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關問卷裡問項先後順序的說法，何者正確？①為防回答者沒耐性，最好開始就問有壓迫性的問題', '["為避免回答者不仔細看題目，最好不按邏輯順序交雜詢問不同主題問項", "問卷問項先後順序影響回 答者作答的現象稱順序效果（order effect）", "順序效果對持中立態度者與低教育程度者影響較大  ⑤先 問一般問題再問特殊問題的順序安排稱為漏斗順序（funnel sequence）", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03182', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '請挑出有關郵寄問卷、電話訪談、與面對面訪談的錯誤敘述：', '["以成本高低排序：面對面訪談＞電話訪談＞郵寄問卷", "以速度快慢排序：面對面訪談＞電話訪談＞郵寄問卷", "以回答率高低排序：面對面訪談＞電話訪談＞郵寄問卷", "以社會期望偏誤高低排序：面對面訪談＞電話訪談＞郵寄問卷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03183', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關紥根理論（grounded theory）的敘述，何者正確？①它是一個從上往下的演繹過程  ②主旨在否證研究', '["不斷在資料、理論及彼此之間持續比較", "理論抽樣（theoretical sampling）是 挑取受訪者的關鍵  ⑤理論飽和（theoretical saturated）是它的終點", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03184', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關焦點團體訪談的敘述，何者正確？', '["是對一群人所進行的共同訪談，它的主題一致、所討論內容和個別訪談相同", "參與者是根據所討論主題的關聯程度隨機抽選出來的", "團體動力也有可能形成壓力，讓參與者不敢或不願表示意見", "所蒐集資料的訊息集中、有系統性，比較容易進行分析"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03185', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '為避免社會工作評估過程中，社會工作者的主觀期望有意無意間影響了案主的回答，我們可考慮採用：', '["開放實驗設計", "霍桑實驗設計", "單盲實驗設計", "雙盲實驗設計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
